mapper.select:
select



order by s.school_year desc, s.term desc, sc.class_id, co.course_id, cct.cct_id
limit #{pageSize} offset #{offset}

select count(*)
from class_course_teacher
where semester_id = #{semesterId}
  and class_id = #{classId}
  and course_id = #{courseId}

    and cct_id != #{cctId}
